"use strict";parserFactory.register("requiemtls.com",()=>new RequiemtlsParser);class RequiemtlsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.eplisterfull a")].map(e=>({sourceUrl:e.href,title:e.querySelector(".epl-num").textContent+" "+e.querySelector(".epl-title").textContent})).reverse()}findContent(e){return Parser.findConstrutedContent(e)}extractSubject(e){return[...e.querySelectorAll("div.info-content .genxed a")].map(e=>e.textContent.trim()).join(", ")}extractDescription(e){return e.querySelector("div.entry-content").textContent.trim()}extractTitleImpl(e){return e.querySelector(".entry-title")}findCoverImageUrl(e){return e.querySelector("div.thumbook img.ts-post-image")?.src??null}async fetchChapter(e){let t=(await HttpClient.wrapFetch(e)).responseXML;return this.buildChapter(t,e)}buildChapter(e,t){let r=Parser.makeEmptyDocForContent(t),n=r.dom.createElement("h1");n.textContent=e.querySelector(".entry-title").textContent,r.content.appendChild(n);let l=r.dom.createElement("div"),o=e.querySelector(".entry-content");for(let e of[...o.childNodes])l.appendChild(e);let c=new RegExp(/requiem_tnr_.*?(,|")/,"s"),i=e.querySelector(".entry-content").outerHTML.match(c)?.[0];return i=i.replaceAll("\n","").replaceAll("'","").replaceAll(" ","").slice(0,-1),l.style.fontFamily=i,r.content.appendChild(l),r.dom}}